        All = all;

        var byCountryMutable = new Dictionary<CountryCode, List<Subdivision>>();
        foreach (var sub in all)
        {
            var cc = sub.CountryIso31661Alpha2Code;
            if (!byCountryMutable.TryGetValue(cc, out var list))
            {
                list = new List<Subdivision>();
                byCountryMutable[cc] = list;
            }

            list.Add(sub);
        }

        var byCountry = new Dictionary<CountryCode, IReadOnlyList<Subdivision>>();
        foreach (var kvp in byCountryMutable)
            byCountry[kvp.Key] = kvp.Value.ToArray();

        ByCountry = byCountry.ToFrozenDictionary();
    }

    /// <summary>
    /// Wire-nav step of the two-pass populate pattern. Invoked exactly
    /// once by <c>GeoDataInitializer</c> after every catalog's first-pass
    /// static ctor has run. Mutates each subdivision's <c>Country</c> +
    /// <c>ParentSubdivision</c> navs via the friend-assembly
    /// <c>internal set</c> accessors.
    /// </summary>
    internal static void WireNav()
    {
        foreach (var sub in All)
        {
            if (CountryLookup.ByCode.TryGetValue(sub.CountryIso31661Alpha2Code, out var country))
                sub.Country = country;

            if (sub.ParentSubdivisionIso31662Code is { } parentCode
                && ByCode.TryGetValue(parentCode, out var parent))
            {
                sub.ParentSubdivision = parent;
            }
        }
    }
